1	'use strict';
2	// E-260 (v23.3) — COOKIE EVIDENCE. THE PECR BREACH WE HAVE BEEN BLIND TO SINCE DAY ONE.
3	//
4	// WHAT WE COULD NEVER SEE:
5	//   Every finding this engine has ever made was read out of CRAWLED HTML. But the actual PECR breach is not in the
6	//   HTML. It is in BEHAVIOUR:
7	//       * cookies WRITTEN TO THE BROWSER before the user has consented to anything;
8	//       * network requests fired at Google Analytics, Meta, Hotjar and 50,000 other tracker hosts, on page load,
9	//         before any banner is touched.
10	//   You cannot see any of that by fetching a page and running a regex over it. We have been auditing law firms on
11	//   cookie compliance while structurally unable to observe a single cookie.
12	//
13	// THE LAW, precisely:
14	//   PECR reg.6(1)-(2): a person may not store information, or gain access to information stored, in the terminal
15	//   equipment of a subscriber UNLESS the subscriber is provided with clear information AND HAS GIVEN CONSENT.
16	//   reg.6(4) exempts only what is STRICTLY NECESSARY for a service the subscriber has explicitly requested.
17	//   Analytics is not strictly necessary. The ICO has said so repeatedly. Advertising plainly is not.
18	//   Consent must be a positive act (UK GDPR Art.4(11)); it cannot be assumed from mere continued browsing.
19	//
20	//   THEREFORE: a non-essential cookie present on FIRST LOAD, with NO interaction of any kind, is a completed breach
21	//   of PECR reg.6. There is nothing to interpret. The cookie is either there before consent, or it is not.
22	//   Maximum penalty under PECR (as amended, and see the Data (Use and Access) Act 2025 which raises PECR caps
23	//   towards UK GDPR levels): the ICO's own enforcement band.
24	//
25	// HOW WE OBSERVE IT (and why this needs no SSH):
26	//   A real Chromium, via Playwright, inside the mint runner. Fresh, isolated browser context (no profile, no prior
27	//   state). Navigate. Touch NOTHING. Then read document.cookie + the CDP cookie jar + every network request the
28	//   page fired. Classify each against the tracker oracle (EasyPrivacy: 50,079 tracker hosts; Open Cookie Database:
29	//   2,239 purpose-labelled cookies, 1,234 of which require consent).
30	//   The Hetzner box's renderer returns only HTML and would need a code change to return cookies, which needs SSH we
31	//   do not have. This runs on the GitHub Actions runner instead: versioned in git, free, nothing to babysit.
32	//
33	// FAIL-OPEN, ALWAYS: if Playwright is unavailable, if the browser cannot launch, if the site times out — we return
34	// null and assert NOTHING. A missing observation is not evidence of compliance, and it is certainly not evidence of
35	// a breach. We never guess at behaviour we did not see.
36	
37	const fs = require('fs');
38	const path = require('path');
39	
40	let _oracle = null;
41	function oracle() {
42	  if (_oracle) return _oracle;
43	  try {
44	    _oracle = JSON.parse(fs.readFileSync(path.join(__dirname, '..', '..', '..', 'data', 'tracker-oracle.json'), 'utf8'));
45	    _oracle._domains = new Set(_oracle.tracker_domains || []);
46	  } catch (_e) { _oracle = { _domains: new Set(), cookie_purposes: {}, sources: {} }; }
47	  return _oracle;
48	}
49	
50	function _isTrackerHost(host) {
51	  const o = oracle();
52	  host = String(host || '').toLowerCase();
53	  if (o._domains.has(host)) return true;
54	  // a subdomain of a known tracker host is a tracker host
55	  const parts = host.split('.');
56	  for (let i = 1; i < parts.length - 1; i++) {
57	    if (o._domains.has(parts.slice(i).join('.'))) return true;
58	  }
59	  return false;
60	}
61	
62	// Classify a cookie by NAME against the Open Cookie Database. Unknown => we do NOT assume it needs consent.
63	// Over-claiming here would be a false positive on a legal claim, which is the one thing we cannot afford.
64	function _classifyCookie(name) {
65	  const o = oracle();
66	  const n = String(name || '').toLowerCase();
67	  const hit = o.cookie_purposes[n];
68	  if (hit) return { known: true, category: hit.category, consent_required: !!hit.consent_required, platform: hit.platform, description: hit.description };
69	  // Prefix families the Open Cookie DB records generically (_ga_XXXX, _gid, _fbp...). Only the unambiguous ones.
70	  const FAM = [
71	    [/^_ga($|_)/, 'Analytics', 'Google Analytics'],
72	    [/^_gid$/, 'Analytics', 'Google Analytics'],
73	    [/^_gcl_/, 'Marketing', 'Google Ads'],
74	    [/^_fbp$|^_fbc$/, 'Marketing', 'Meta Pixel'],
75	    [/^_hj/, 'Analytics', 'Hotjar'],
76	    [/^__utm/, 'Analytics', 'Google Analytics (legacy)'],
77	    [/^_clck$|^_clsk$/, 'Analytics', 'Microsoft Clarity'],
78	    [/^_uetsid|^_uetvid/, 'Marketing', 'Microsoft Advertising'],
79	    [/^li_sugr$|^bcookie$|^lidc$/, 'Marketing', 'LinkedIn'],
80	  ];
81	  for (const [rx, cat, plat] of FAM) {
82	    if (rx.test(n)) return { known: true, category: cat, consent_required: true, platform: plat, description: '' };
83	  }
84	  return { known: false, category: null, consent_required: false };
85	}
