87	/**
88	 * observe(url) -> { ok, pre_consent: { cookies:[], tracker_requests:[] }, cmp, ms } | null
89	 * Loads the page in a FRESH context and touches nothing. Everything observed is, by construction, PRE-CONSENT.
90	 */
91	async function observe(url, opts) {
92	  // E-267: resolve the browser driver robustly, and SAY why if we cannot. `require('playwright')` was failing in
93	  // the mint (the driver installs into a node_modules the build could not resolve), observe() returned null, and
94	  // the fail-open path was SILENT — so the cookie collector produced nothing and no log said why. A missing
95	  // browser is a legitimate fail-open, but it must be OBSERVABLE, not invisible.
96	  let chromium = null, _drv = '';
97	  for (const mod of ['playwright', 'playwright-core', '@playwright/test']) {
98	    try { const m = require(mod); chromium = m.chromium || (m.default && m.default.chromium); if (chromium) { _drv = mod; break; } } catch (_e) { /* try next */ }
99	  }
100	  if (!chromium) { console.error('[cookie-evidence] no playwright driver resolvable (tried playwright, playwright-core, @playwright/test) — install it in the mint or set COOKIE_EVIDENCE=0'); return null; }
101	
102	  const t0 = Date.now();
103	  let browser = null;
104	  try {
105	    browser = await chromium.launch({ args: ['--no-sandbox', '--disable-dev-shm-usage'] });
106	    const ctx = await browser.newContext({
107	      userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0 Safari/537.36',
108	      viewport: { width: 1366, height: 900 },
109	    });
110	    const page = await ctx.newPage();
111	
112	    const trackerReqs = [];
113	    page.on('request', (r) => {
114	      try {
115	        const h = new URL(r.url()).hostname;
116	        if (_isTrackerHost(h)) trackerReqs.push({ host: h, url: r.url().slice(0, 180), type: r.resourceType() });
117	      } catch (_e) { /* ignore */ }
118	    });
119	
120	    // E-270: waitUntil MUST NOT be 'networkidle'. The very sites we are hunting for PECR breaches — analytics- and
121	    // ad-tag-heavy law-firm sites — keep the network busy indefinitely, so 'networkidle' NEVER fires and goto burns
122	    // its entire timeout on exactly our targets, which (with a cold Chromium launch on the CI runner) blew past the
123	    // 35s outer race every single time and returned null. Cookies and trackers set ON LOAD are already captured: the
124	    // request listener is attached BEFORE goto, and the cookie jar is read AFTER a settle. 'domcontentloaded' + a
125	    // short settle is exactly how Blacklight and Cookiepedia observe pre-consent state. Correct on the merits AND
126	    // inside budget. Internal goto timeout is deliberately tight so a genuinely hung page can never eat the budget.
127	    await page.goto(url, { waitUntil: 'domcontentloaded', timeout: Number((opts && opts.timeoutMs) || 15000) }).catch(() => {});
128	    // We deliberately do NOT click, scroll, or dismiss anything. Whatever exists now existed BEFORE consent.
129	    // Settle long enough for on-load analytics/ad tags to fire and drop their cookies, but no interaction of any kind.
130	    await page.waitForTimeout(3500);
131	
132	    const raw = await ctx.cookies();
133	    const cookies = raw.map((c) => {
134	      const cls = _classifyCookie(c.name);
135	      return {
136	        name: c.name, domain: c.domain, third_party: !String(c.domain || '').replace(/^\./, '').endsWith(new URL(url).hostname.replace(/^www\./, '')),
137	        category: cls.category, consent_required: cls.consent_required, platform: cls.platform || null, known: cls.known,
138	        expires_days: c.expires && c.expires > 0 ? Math.round((c.expires * 1000 - Date.now()) / 86400000) : null,
139	      };
140	    });
141	
142	    // Is there even a consent mechanism? A site that sets trackers AND has no CMP at all is the worst case.
143	    const cmp = await page.evaluate(() => {
144	      const has = (s) => !!document.querySelector(s);
145	      const txt = (document.body && document.body.innerText || '').slice(0, 4000);
146	      return {
147	        tcf: typeof window.__tcfapi === 'function',
148	        onetrust: has('#onetrust-banner-sdk') || typeof window.OneTrust !== 'undefined',
149	        cookiebot: has('#CybotCookiebotDialog') || typeof window.Cookiebot !== 'undefined',
150	        civic: has('#ccc') || has('.ccc-widget'),
151	        cookieyes: has('.cky-consent-container'),
152	        banner_text: /cookie|consent|privacy/i.test(txt),
153	      };
154	    }).catch(() => ({}));
155	
156	    const seen = new Set();
157	    const uniqTrackers = trackerReqs.filter((r) => (seen.has(r.host) ? false : (seen.add(r.host), true)));
158	    await browser.close(); browser = null;
159	
160	    return {
161	      ok: true,
162	      ms: Date.now() - t0,
163	      pre_consent: {
164	        cookies,
165	        non_essential: cookies.filter((c) => c.consent_required),
166	        tracker_requests: uniqTrackers,
167	      },
168	      cmp,
169	      oracle: (oracle().sources || {}),
170	    };
171	  } catch (_e) {
172	    try { if (browser) await browser.close(); } catch (_e2) {}
173	    console.error('[cookie-evidence] browser observation failed for ' + url + ': ' + String((_e && _e.message) || _e).slice(0, 120));
174	    return null;   // FAIL-OPEN, but never silent
175	  }
176	}
