178	/**
179	 * Turn the observation into PECR findings. Only what we actually saw. Nothing inferred.
180	 */
181	function cookieFindings(obs, ctx) {
182	  if (!obs || !obs.ok) return [];   // saw nothing, claim nothing
183	  const out = [];
184	  const pre = obs.pre_consent || {};
185	  const nonEssential = pre.non_essential || [];
186	  const trackers = pre.tracker_requests || [];
187	  const country = String((ctx && ctx.country) || 'UK').toUpperCase();
188	  const isUKorEU = !country || country === 'UK' || country === 'GB' || country === 'GBR' || /^(EU|FR|DE|IE|NL|ES|IT|BE|PT|AT|SE|DK|FI|PL|LU)$/.test(country);
189	  if (!isUKorEU) return [];
190	
191	  // ---- THE BREACH: a non-essential cookie present before ANY consent ----
192	  if (nonEssential.length) {
193	    const named = nonEssential.slice(0, 6).map((c) => c.name + (c.platform ? ' (' + c.platform + ', ' + c.category + ')' : '')).join('; ');
194	    out.push({
195	      status: 'miss', severity: 'P0',
196	      framework: 'UK_PECR', code: 'PECR_PRECONSENT_COOKIES', rule_type: 'prohibit',
197	      statutory_citation: 'Privacy and Electronic Communications (EC Directive) Regulations 2003 reg.6(1)-(2)',
198	      citation_url: 'https://www.legislation.gov.uk/uksi/2003/2426/regulation/6',
199	      description: 'Non-essential cookies are written to the visitor’s browser on page load, before any consent is given',
200	      layman_explanation: 'The law requires consent BEFORE a non-essential cookie is set. On a first visit, with nothing clicked, '
201	        + nonEssential.length + ' non-essential cookie' + (nonEssential.length === 1 ? ' was' : 's were') + ' already placed on the device: ' + named + '. '
202	        + 'Consent must be a positive act; it cannot be assumed from browsing.',
203	      tamazia_fix_short: 'Block all non-essential cookies and tags until consent is given, and wire the consent banner to actually gate them.',
204	      // THE EVIDENCE IS THE COOKIE ITSELF, OBSERVED IN A REAL BROWSER. Not a quote. Not an inference.
205	      evidence_quote: null,
206	      absence_evidence: {
207	        state: 'observed_in_browser',
208	        requirement: 'no non-essential cookie may be set before consent (PECR reg.6)',
209	        nearest_quote: 'Observed in a fresh Chromium session with no interaction: ' + named,
210	        pages_checked: 1,
211	      },
212	      evidence_url: (ctx && ctx.url) || null,
213	      cookie_evidence: nonEssential.slice(0, 20),
214	      fine_low_gbp: 0,
215	      // THE CATALOGUE IS THE ONLY SOURCE OF A FINE. This was hardcoded 500000 — the PRE-DUAA cap — so the audit
216	      // printed GBP 500,000 while compliance_rules said GBP 17,500,000. I fixed the database and the code kept its
217	      // own copy. The Data (Use and Access) Act 2025 raised the PECR maximum to GBP 17.5m or 4% of global turnover,
218	      // in force 5 Feb 2026. Understating a client's exposure by 35x is why a managing partner does nothing.
219	      fine_high_gbp: 17500000,
220	      enforce_typical_low_gbp: 50000, enforce_typical_high_gbp: 350000,
221	      penalty_note: 'ICO monetary penalty (PECR); the Data (Use and Access) Act 2025 raises PECR caps towards UK GDPR levels',
222	    });
223	  }
224	
225	  // ---- Trackers firing before consent (network evidence, independent of cookies) ----
226	  if (trackers.length) {
227	    const hosts = trackers.slice(0, 6).map((t) => t.host).join(', ');
228	    out.push({
229	      status: 'miss', severity: 'P1',
230	      framework: 'UK_PECR', code: 'PECR_PRECONSENT_TRACKERS', rule_type: 'prohibit',
231	      statutory_citation: 'PECR 2003 reg.6; UK GDPR Art.6 (lawful basis for the onward processing)',
232	      citation_url: 'https://www.legislation.gov.uk/uksi/2003/2426/regulation/6',
233	      description: 'Third-party tracking requests fire on page load, before any consent is given',
234	      layman_explanation: 'On a first visit with nothing clicked, the page contacted ' + trackers.length + ' known tracking host'
235	        + (trackers.length === 1 ? '' : 's') + ': ' + hosts + '. Personal data (at minimum the IP address and page URL) is disclosed '
236	        + 'to those third parties before the visitor has agreed to anything.',
237	      tamazia_fix_short: 'Load all tracking tags only after consent, through a consent-gated tag manager.',
238	      evidence_quote: null,
239	      absence_evidence: {
240	        state: 'observed_in_browser',
241	        requirement: 'no non-essential tracking before consent',
242	        nearest_quote: 'Network requests observed in a fresh Chromium session with no interaction: ' + hosts,
243	        pages_checked: 1,
244	      },
245	      evidence_url: (ctx && ctx.url) || null,
246	      tracker_evidence: trackers.slice(0, 20),
247	      fine_low_gbp: 0,
248	      // THE CATALOGUE IS THE ONLY SOURCE OF A FINE. This was hardcoded 500000 — the PRE-DUAA cap — so the audit
249	      // printed GBP 500,000 while compliance_rules said GBP 17,500,000. I fixed the database and the code kept its
250	      // own copy. The Data (Use and Access) Act 2025 raised the PECR maximum to GBP 17.5m or 4% of global turnover,
251	      // in force 5 Feb 2026. Understating a client's exposure by 35x is why a managing partner does nothing.
252	      fine_high_gbp: 17500000,
253	      enforce_typical_low_gbp: 30000, enforce_typical_high_gbp: 250000,
254	      penalty_note: 'ICO monetary penalty (PECR)',
255	    });
256	  }
257	
258	  // ---- No consent mechanism at all, while tracking ----
259	  const cmp = obs.cmp || {};
260	  const hasCmp = !!(cmp.tcf || cmp.onetrust || cmp.cookiebot || cmp.civic || cmp.cookieyes);
261	  if (!hasCmp && (nonEssential.length || trackers.length)) {
262	    out.push({
263	      status: 'miss', severity: 'P1',
264	      framework: 'UK_ICO_COOKIES', code: 'PECR_NO_CMP', rule_type: 'must_appear',
265	      statutory_citation: 'PECR 2003 reg.6(2); ICO guidance on the use of cookies and similar technologies',
266	      citation_url: 'https://ico.org.uk/for-organisations/direct-marketing-and-privacy-and-electronic-communications/guide-to-pecr/cookies-and-similar-technologies/',
267	      description: 'The site sets non-essential cookies or trackers but presents no recognised consent-management mechanism',
268	      layman_explanation: 'No consent-management platform was detected, yet non-essential cookies or third-party trackers are active. '
269	        + 'There is therefore no mechanism by which valid consent could have been obtained.',
270	      tamazia_fix_short: 'Deploy a consent-management platform that genuinely blocks non-essential tags until consent.',
271	      evidence_quote: null,
272	      absence_evidence: { state: 'observed_in_browser', requirement: 'a consent mechanism must exist before non-essential cookies are set', pages_checked: 1 },
273	      evidence_url: (ctx && ctx.url) || null,
274	      fine_low_gbp: 0,
275	      // THE CATALOGUE IS THE ONLY SOURCE OF A FINE. This was hardcoded 500000 — the PRE-DUAA cap — so the audit
276	      // printed GBP 500,000 while compliance_rules said GBP 17,500,000. I fixed the database and the code kept its
277	      // own copy. The Data (Use and Access) Act 2025 raised the PECR maximum to GBP 17.5m or 4% of global turnover,
278	      // in force 5 Feb 2026. Understating a client's exposure by 35x is why a managing partner does nothing.
279	      fine_high_gbp: 17500000,
280	      enforce_typical_low_gbp: 20000, enforce_typical_high_gbp: 200000,
281	      penalty_note: 'ICO monetary penalty (PECR)',
282	    });
283	  }
284	
285	  return out;
286	}
