2	// tools/lib/safe-path.js - the one allowlist gate for a dynamic path.join/path.resolve component
3	// (a filename, a CLI argument, or a directory-listing entry).
4	//
5	// WHY THIS FILE EXISTS: Semgrep's javascript.lang.security.audit.path-traversal rule fires on any
6	// path.join/path.resolve call whose argument is not a string literal, regardless of whether the
7	// value is genuinely attacker-controlled (catalogue/compile.js, catalogue/linters/lib.js and
8	// tools/facts-abstain/check.js all build paths from fs.readdirSync() entries or CLI argv, which are
9	// operator/repo-controlled in this codebase, not network input). Rather than suppress the finding,
10	// every such call site routes its dynamic component(s) through this module first: each one is
11	// checked against an allowlist shape BEFORE it reaches path.join, and a component that fails the
12	// allowlist throws rather than silently resolving outside its intended directory (Constitution Rule
13	// 4: fail closed). This is the single door for that check, so four call sites do not grow four
14	// slightly different traversal guards (the clone class jscpd exists to catch elsewhere in this
15	// repo).
16	//
17	// Three distinct shapes are validated, because they have different legitimate semantics:
18	//   - a PATH COMPONENT (one segment: a bare filename or "name.ext", e.g. "uk-legal.json",
19	//     "uk-legal.QA.md") - used for entries that come from fs.readdirSync() output. These must never
20	//     contain a path separator, "." or ".." alone, or a null byte.
21	//   - a RELATIVE PATH (one or more segments, e.g. "catalogue/packs" or "out/catalogue.v1.json") -
22	//     used for CLI-supplied WRITE/config path arguments (compile.js's --out, --stamp-file, --packs)
23	//     that legitimately name a nested location chosen by the trusted operator, RESOLVED AGAINST A
24	//     FIXED BASE. These may contain separators, but must be genuinely RELATIVE: no segment may be
25	//     ".." (the traversal vector), the path may not be ABSOLUTE (an absolute path discards the base
26	//     under path.resolve and so escapes just as surely as "..", CR safe-path.js:43), and no null
27	//     byte is ever permitted.
28	//   - a SCAN PATH (a READ target: a file or directory an operator/caller names for a gate to READ,
29	//     e.g. facts-abstain/check.js's scan argv and the catalogue linters' scan dirs) - CONSUMER
30	//     AUDIT (CR safe-path.js:43): unlike a base-relative WRITE arg, a scan target is used DIRECTLY,
31	//     not path.resolve(base, p)'d against a base it could discard, and it legitimately arrives
32	//     ABSOLUTE (an already-safeJoin-validated internal path the compiler hands its linters, or an
33	//     operator naming a bundle/pack anywhere on disk). So a scan path accepts EITHER an absolute
34	//     path OR a genuinely-relative one with no ".." segment; a relative one is still resolved
35	//     against the base and its traversal guarded. Null bytes are never permitted. Directory ENTRIES
36	//     discovered under a scan path are still routed through safeJoin regardless.
37	const path = require('path');
38	
39	const SAFE_COMPONENT_RX = /^[A-Za-z0-9][A-Za-z0-9._-]*$/;
40	
41	// isEmptyOrHasNullByte(p) -> true for a non-string, an empty string, or a string carrying a null byte.
42	// The shared first gate of all three shapes (never a valid path), so each predicate opens with one call
43	// instead of repeating the same two guards.
44	function isEmptyOrHasNullByte(p) {
45	  if (typeof p !== 'string' || p.length === 0) return true;
46	  return p.includes('\0');
47	}
48	
49	function isSafePathComponent(component) {
50	  if (isEmptyOrHasNullByte(component)) return false;
51	  if (component === '.' || component === '..') return false;
52	  if (component.includes('/') || component.includes('\\')) return false;
53	  return SAFE_COMPONENT_RX.test(component);
54	}
55	
56	function isSafeRelativePath(p) {
57	  if (isEmptyOrHasNullByte(p)) return false;
58	  // CR (safe-path.js:43): a "relative" path must actually BE relative. An ABSOLUTE path
59	  // (/etc/passwd, C:\Windows) carries no ".." segment yet still escapes the intended base
60	  // entirely: path.resolve(base, absolute) discards base and resolves to the absolute location.
61	  // Rejecting it here closes that hole for every consumer at once, so the whole shared contract
62	  // rejects absolute AND traversal consistently (compile.js CLI args, catalogue linters,
63	  // facts-abstain scan paths), not just the "../" vector.
64	  if (path.isAbsolute(p)) return false;
65	  const segments = p.split(/[\\/]+/).filter((s) => s.length > 0);
66	  if (segments.length === 0) return false;
67	  return segments.every((seg) => seg !== '.' && seg !== '..');
68	}
69	
70	// isSafeScanPath(p) -> true for a READ-scan target (see file header, third shape). Accepts an
71	// ABSOLUTE path (used directly, so there is no base for it to escape - the compiler's own
72	// already-validated linter paths and operator-named read targets both arrive this way), OR a
73	// genuinely-relative path with no ".." traversal segment. Never a null byte, never empty. This is
74	// the READ-side counterpart to isSafeRelativePath (the WRITE/config-arg side, which resolves against
75	// a base and so MUST keep rejecting absolute). One door for the read-scan shape so lib.js and
76	// facts-abstain do not grow two subtly-different absolute-path branches (CR safe-path.js:43 consumer
77	// audit).
78	function isSafeScanPath(p) {
79	  if (isEmptyOrHasNullByte(p)) return false;
80	  if (path.isAbsolute(p)) return true;
81	  return isSafeRelativePath(p);
82	}
83	
84	// assertSafe(value, isValid, opts, defaultLabel, reason) -> value. THE shared assert body for all
85	// three shapes: run the shape's own predicate and, on failure, throw opts.ErrorClass (default Error)
86	// with a "<label>: <value> <reason>" message. Extracted so the three public asserts are one-line
87	// wrappers around one door, not three structurally-identical throw blocks (CodeScene Code Duplication;
88	// this is exactly the clone class jscpd exists to catch elsewhere in the repo).
89	function assertSafe(value, isValid, opts, message) {
90	  const o = opts || {};
91	  if (!isValid(value)) {
92	    const ErrorClass = o.ErrorClass || Error;
93	    throw new ErrorClass((o.label || message.defaultLabel) + ': ' + JSON.stringify(value) + ' ' + message.reason);
94	  }
95	  return value;
96	}
97	
98	// assertSafePathComponent(component, opts) -> component. THROWS (opts.ErrorClass, default Error) on
99	// anything that is not a single, traversal-free path segment. opts.label names the call site.
100	function assertSafePathComponent(component, opts) {
101	  return assertSafe(component, isSafePathComponent, opts, {
102	    defaultLabel: 'path component',
103	    reason: 'is not a safe path component (must match ' + SAFE_COMPONENT_RX + ', no "." or ".." alone, no path separators, no null byte)',
104	  });
105	}
106	
107	// assertSafeRelativePath(p, opts) -> p. THROWS on an absolute path, a null byte, or any
108	// ".."/"." traversal segment.
109	function assertSafeRelativePath(p, opts) {
110	  return assertSafe(p, isSafeRelativePath, opts, {
111	    defaultLabel: 'path',
112	    reason: 'is not a safe relative path (must be relative, not absolute; no ".."/"." traversal segments; no null byte; non-empty)',
113	  });
114	}
115	
116	// assertSafeScanPath(p, opts) -> p. THROWS on a null byte, an empty/non-string, or a RELATIVE path
117	// carrying a ".."/"." traversal segment. An absolute path is accepted (see isSafeScanPath).
118	function assertSafeScanPath(p, opts) {
119	  return assertSafe(p, isSafeScanPath, opts, {
120	    defaultLabel: 'scan path',
121	    reason: 'is not a safe scan path (absolute is allowed; a relative one must carry no ".."/"." traversal segments; no null byte; non-empty)',
122	  });
123	}
124	
125	// safeJoin(baseDir, components, opts) -> path.join(baseDir, ...components), after asserting every
126	// entry in `components` is a safe single segment (assertSafePathComponent) AND that the resolved
127	// result stays inside baseDir (belt-and-braces: even an allowlisted component could theoretically
128	// still escape on a platform with unusual path semantics, so the resolved path is re-checked too).
129	// assertInsideBase(resolvedBase, resolvedJoined, opts) -> throws when the resolved join landed
130	// outside the base directory (the belt-and-braces escape check safeJoin delegates to).
131	function assertInsideBase(resolvedBase, resolvedJoined, opts) {
132	  if (resolvedJoined === resolvedBase || resolvedJoined.startsWith(resolvedBase + path.sep)) return;
133	  const o = opts || {};
134	  const ErrorClass = o.ErrorClass || Error;
135	  throw new ErrorClass(
136	    (o.label || 'safeJoin') + ': resolved path ' + JSON.stringify(resolvedJoined)
137	    + ' escapes base directory ' + JSON.stringify(resolvedBase)
138	  );
139	}
140	
141	function safeJoin(baseDir, components, opts) {
142	  const parts = Array.isArray(components) ? components : [components];
143	  for (const c of parts) assertSafePathComponent(c, opts);
144	  const joined = path.join(baseDir, ...parts);
145	  assertInsideBase(path.resolve(baseDir), path.resolve(joined), opts);
146	  return joined;
147	}
148	
149	module.exports = {
150	  SAFE_COMPONENT_RX,
151	  isSafePathComponent,
152	  isSafeRelativePath,
153	  isSafeScanPath,
154	  assertSafePathComponent,
155	  assertSafeRelativePath,
156	  assertSafeScanPath,
157	  safeJoin,
158	};
